		}

		field := values.Field(i)
		fieldValue := utils.GetReflectValue(field)
		fieldKind := utils.GetReflectKind(fieldValue.Type())
		switch fieldKind {
		case reflect.Array, reflect.Slice:
			for i := 0; i < field.Len(); i++ {
