			}
		case reflect.Struct:
			var serializedValue []string
			subValues := utils.GetReflectValue(fieldValue)
			for j := 0; j < subValues.NumField(); j++ {
				subKey, found := subValues.Type().Field(j).Tag.Lookup("headerParam")
				if !found {
